DELIMITER $$
--
-- Functions
--
CREATE DEFINER=`root`@`localhost` FUNCTION `generate_lease_number` () RETURNS VARCHAR(255) CHARSET utf8mb4 READS SQL DATA BEGIN
    DECLARE current_ym VARCHAR(6);
    DECLARE next_num INT;
    DECLARE new_lease_number VARCHAR(255);
    
    SET current_ym = DATE_FORMAT(NOW(), '%Y%m');
    
    -- Get or create sequence for current year-month
    VALUES (current_ym, 0)
    ON DUPLICATE KEY UPDATE last_number = last_number + 1;
    
    -- Get the next number
    SELECT last_number INTO next_num 
    FROM lease_sequence 
    WHERE yr_month = current_ym;
    
    SET new_lease_number = CONCAT('LSE-', current_ym, LPAD(next_num, 3, '0'));
    
    RETURN new_lease_number;
END$$

DELIMITER ;

