--
-- Triggers `consolidated_billings`
--
DELIMITER $$
CREATE TRIGGER `after_consolidated_billing_insert` AFTER INSERT ON `consolidated_billings` FOR EACH ROW BEGIN
    DECLARE prev_balance DECIMAL(15,2);
    DECLARE new_balance DECIMAL(15,2);
    DECLARE trans_number VARCHAR(50);
    DECLARE trans_description VARCHAR(255);
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        VALUES ('after_consolidated_billing_insert', 
                CONCAT('Error: ', NEW.billing_number, ' - ', NEW.description),
                NEW.id);
    END;
    
    -- Only create transaction for relevant statuses
    IF NEW.status IN ('pending', 'sent', 'paid', 'partial') THEN
        
        -- Get the previous balance for this user
        SELECT balance INTO prev_balance
        FROM transactions
        WHERE user_id = NEW.user_id
        ORDER BY transaction_date DESC, id DESC
        LIMIT 1;
        
        -- If no previous transaction, start with 0
        IF prev_balance IS NULL THEN
            SET prev_balance = 0;
        END IF;
        
        -- Calculate new balance
        SET new_balance = prev_balance + NEW.total_amount;
        
        -- Generate transaction number using billing number parts
        SET trans_number = CONCAT(
            'TXN-',
            DATE_FORMAT(NEW.billing_date, '%Y%m%d'),
            '-',
            SUBSTRING_INDEX(SUBSTRING_INDEX(NEW.billing_number, '-', -2), '-', 1)
        );
        
        -- Create description
        SET trans_description = CONCAT(
            'Consolidated Invoice - ',
            NEW.billing_number,
            ' (', 
            DATE_FORMAT(NEW.billing_date, '%M %Y'),
            ')'
        );
        
        -- Insert transaction record
            user_id,
            transaction_number,
            transaction_date,
            type,
            description,
            amount,
            currency,
            direction,
            balance,
            reference,
            status,
            created_at,
            updated_at
        ) VALUES (
            NEW.user_id,
            trans_number,
            NEW.billing_date,
            'invoice',
            trans_description,
            NEW.total_amount,
            COALESCE(NEW.currency, 'USD'),
            'in',
            new_balance,
            NEW.billing_number,
            CASE 
                WHEN NEW.status = 'paid' THEN 'completed'
                WHEN NEW.status = 'partial' THEN 'partial'
                ELSE 'pending'
            END,
            NOW(),
            NOW()
        );
        
    END IF;
    
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `after_consolidated_billing_update` AFTER UPDATE ON `consolidated_billings` FOR EACH ROW BEGIN
    DECLARE trans_exists INT;
    
    -- Check if transaction exists
    SELECT COUNT(*) INTO trans_exists
    FROM transactions
    WHERE reference = NEW.billing_number AND type = 'invoice';
    
    -- Handle status changes
    IF trans_exists > 0 THEN
        -- Status changed to paid/partial
        IF NEW.status IN ('paid', 'partial') AND OLD.status IN ('pending', 'sent') THEN
            UPDATE transactions 
            SET 
                status = CASE 
                    WHEN NEW.status = 'paid' THEN 'completed'
                    WHEN NEW.status = 'partial' THEN 'partial'
                    ELSE status
                END,
                updated_at = NOW()
            WHERE reference = NEW.billing_number AND type = 'invoice';
        END IF;
        
        -- Status changed to cancelled
        IF NEW.status = 'cancelled' AND OLD.status != 'cancelled' THEN
            UPDATE transactions 
            SET 
                status = 'cancelled',
                updated_at = NOW()
            WHERE reference = NEW.billing_number AND type = 'invoice';
        END IF;
        
        -- Amount changed (rare, but handle it)
        IF NEW.total_amount != OLD.total_amount THEN
            -- Recalculate balance for this and all subsequent transactions
            UPDATE transactions 
            SET 
                amount = NEW.total_amount,
                description = CONCAT('Updated: ', NEW.description),
                updated_at = NOW()
            WHERE reference = NEW.billing_number AND type = 'invoice';
            
            -- Note: You may need to recalculate all subsequent balances
            -- This is a complex operation and might be better handled in application code
        END IF;
    END IF;
    
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `before_consolidated_billings_update` BEFORE UPDATE ON `consolidated_billings` FOR EACH ROW BEGIN
    IF NEW.exchange_rate IS NOT NULL AND (NEW.total_amount IS NOT NULL OR NEW.paid_amount IS NOT NULL) THEN
        SET NEW.total_amount_kes = NEW.total_amount * NEW.exchange_rate,NEW.paid_amount_kes = NEW.paid_amount * NEW.exchange_rate;
    END IF;
END
$$
